  const [manualCapacity, setManualCapacity] = useState(asset.hdd || '');

  const isManual = shredType === 'manual';

  return React.createElement('div', { className: 'modal-overlay', onClick: onClose },
    React.createElement('div', { className: 'modal', onClick: e => e.stopPropagation() },
      React.createElement('div', { className: 'modal-title' }, 
        isManual ? '📋 Log Drive for Shred' : '🔥 Create Shred Record'
      ),

      isManual && React.createElement('div', null,
        React.createElement('div', { className: 'modal-field' },
          React.createElement('div', { className: 'modal-label' }, 'Drive Serial'),
          React.createElement('input', { className: 'modal-input', value: manualSerial, onChange: e => setManualSerial(e.target.value), placeholder: 'Enter drive serial number' })
        ),
        React.createElement('div', { className: 'modal-field' },
          React.createElement('div', { className: 'modal-label' }, 'Drive Model'),
          React.createElement('input', { className: 'modal-input', value: manualModel, onChange: e => setManualModel(e.target.value), placeholder: 'e.g. WD Blue 500GB' })
        ),
        React.createElement('div', { className: 'modal-field' },
          React.createElement('div', { className: 'modal-label' }, 'Interface'),
          React.createElement('input', { className: 'modal-input', value: manualInterface, onChange: e => setManualInterface(e.target.value), placeholder: 'e.g. SATA, NVMe' })
        ),
        React.createElement('div', { className: 'modal-field' },
          React.createElement('div', { className: 'modal-label' }, 'Capacity'),
          React.createElement('input', { className: 'modal-input', value: manualCapacity, onChange: e => setManualCapacity(e.target.value), placeholder: 'e.g. 500GB' })
        )
      ),

      React.createElement('div', { className: 'modal-field' },
        React.createElement('div', { className: 'modal-label' }, 'HDD Waste Pallet'),
        !createNew && openPallets.length > 0
          ? React.createElement('div', null,
              React.createElement('select', {
                className: 'modal-select', value: selectedPallet,
                onChange: e => setSelectedPallet(e.target.value)
              },
                React.createElement('option', { value: '' }, '-- Select pallet --'),
