      shred_pallet_id: data.pallet_id || null,
      shred_create_new_pallet: data.create_new_pallet || false,
      shred_notes: data.notes || ''
    });
    appsmith.triggerEvent('onShred');
  };

  return React.createElement('div', { className: 'wrap' },
    React.createElement(DriveCard, { asset, shredRecords, openPallets, onShred: handleShred }),
    React.createElement(ShredHistory, { records: shredRecords })
  );
}

